    --text:        #d4d9ef;
    --text-muted:  #7b85a8;
    --text-dim:    #4d5475;
    --accent:      #5b8af7;
    --accent2:     #7c6ef0;
    --accent3:     #4fc3b8;
    --green:       #4caf7d;
    --yellow:      #d4a94a;
    --red:         #e05c5c;
    --orange:      #d4784a;
    --heading1:    #e8ecff;
    --heading2:    #c8d0f5;
    --heading3:    #a8b4e8;
    --code-bg:     #0a0c11;
    --code-border: #252c45;
    --sidebar-w:   310px;
    --sidebar-collapsed-w: 0px;
    --header-h:    56px;
    --font-body:   'Inter', 'Segoe UI', system-ui, sans-serif;
    --font-mono:   'JetBrains Mono', 'Fira Code', 'Cascadia Code', monospace;
    --radius:      6px;
    --radius-lg:   10px;
    --shadow:      0 4px 24px rgba(0,0,0,0.45);
  }

  html { scroll-behavior: smooth; font-size: 15px; }

  body {
    font-family: var(--font-body);
    background: var(--bg);
    color: var(--text);
    line-height: 1.7;
    display: flex;
    flex-direction: column;
    min-height: 100vh;
  }

  /* ─── Top Header Bar ─── */
  .top-bar {
    position: fixed;
    top: 0; left: 0; right: 0;
    height: var(--header-h);
    background: var(--surface);
    border-bottom: 1px solid var(--border);
    display: flex;
    align-items: center;
    padding: 0 20px;
    gap: 16px;
    z-index: 200;
    backdrop-filter: blur(10px);
  }

  .top-bar-logo {
    font-size: 1.05rem;
    font-weight: 700;
    color: var(--heading1);
    letter-spacing: -0.02em;
    white-space: nowrap;
  }

  .top-bar-logo span {
    color: var(--accent);
  }

  .top-bar-meta {
    font-size: 0.78rem;
    color: var(--text-muted);
    margin-left: auto;
    white-space: nowrap;
  }

  .sidebar-toggle {
    background: none;
    border: 1px solid var(--border2);
    color: var(--text-muted);
    width: 32px; height: 32px;
    border-radius: var(--radius);
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    flex-shrink: 0;
    transition: all 0.15s;
  }
  .sidebar-toggle:hover { background: var(--surface2); color: var(--text); }
  .sidebar-toggle svg { width: 16px; height: 16px; }

  /* ─── Layout ─── */
  .layout {
    display: flex;
    padding-top: var(--header-h);
    flex: 1;
  }

  /* ─── Sidebar ─── */
  .sidebar {
    position: fixed;
    top: var(--header-h);
    left: 0;
    bottom: 0;
    width: var(--sidebar-w);
    background: var(--surface);
    border-right: 1px solid var(--border);
    overflow-y: auto;
    overflow-x: hidden;
    z-index: 100;
    transition: transform 0.25s cubic-bezier(0.4,0,0.2,1), width 0.25s cubic-bezier(0.4,0,0.2,1);
    display: flex;
    flex-direction: column;
  }

  .sidebar.collapsed {
    transform: translateX(calc(-1 * var(--sidebar-w)));
  }

  .sidebar::-webkit-scrollbar { width: 4px; }
  .sidebar::-webkit-scrollbar-track { background: transparent; }
  .sidebar::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }

  .sidebar-header {
    padding: 16px 16px 10px;
    font-size: 0.72rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--text-dim);
    border-bottom: 1px solid var(--border);
    flex-shrink: 0;
  }

  .nav-section {
    border-bottom: 1px solid var(--border);
  }

  .nav-section-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 14px;
    font-size: 0.8rem;
    font-weight: 600;
    color: var(--text);
    cursor: pointer;
    user-select: none;
    transition: background 0.12s;
  }
  .nav-section-header:hover { background: var(--surface2); }

  .nav-section-num {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 20px; height: 20px;
    border-radius: 4px;
    background: var(--surface3);
    color: var(--accent);
    font-size: 0.68rem;
    font-weight: 700;
    flex-shrink: 0;
  }

  .nav-section-label { flex: 1; line-height: 1.3; }

  .nav-chevron {
    width: 14px; height: 14px;
    color: var(--text-dim);
    transition: transform 0.2s;
    flex-shrink: 0;
  }
  .nav-section.open .nav-chevron { transform: rotate(90deg); }

  .nav-links {
    display: none;
    padding: 2px 0 6px;
  }
  .nav-section.open .nav-links { display: block; }

  .nav-link {
    display: block;
    padding: 5px 14px 5px 38px;
    font-size: 0.77rem;
    color: var(--text-muted);
    text-decoration: none;
    transition: all 0.1s;
    border-left: 2px solid transparent;
    line-height: 1.35;
  }
  .nav-link:hover { color: var(--text); background: var(--surface2); }
  .nav-link.active { color: var(--accent); border-left-color: var(--accent); background: rgba(91,138,247,0.07); }

  .nav-link-h3 { padding-left: 52px; font-size: 0.72rem; }

  /* ─── Main Content ─── */
  .main-content {
    flex: 1;
    margin-left: var(--sidebar-w);
    transition: margin-left 0.25s cubic-bezier(0.4,0,0.2,1);
    min-width: 0;
    padding: 0;
  }

  .main-content.sidebar-collapsed {
    margin-left: 0;
  }

  /* ─── Document Sections ─── */
  .doc-section {
    border-bottom: 1px solid var(--border);
    position: relative;
  }

  .doc-section-header {
    display: flex;
    align-items: center;
    gap: 14px;
    padding: 24px 40px 24px 36px;
    cursor: pointer;
    user-select: none;
    transition: background 0.15s;
    background: var(--surface);
    position: sticky;
    top: var(--header-h);
    z-index: 10;
    border-bottom: 1px solid var(--border);
  }
  .doc-section-header:hover { background: var(--surface2); }

  .doc-section-badge {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    min-width: 28px; height: 28px;
    padding: 0 8px;
    border-radius: 6px;
    background: var(--surface3);
    color: var(--accent);
    font-size: 0.75rem;
    font-weight: 800;
    letter-spacing: -0.01em;
    flex-shrink: 0;
  }

  .doc-section-title {
    font-size: 1rem;
    font-weight: 700;
    color: var(--heading1);
    flex: 1;
    line-height: 1.3;
  }

  .doc-section-chevron {
    width: 18px; height: 18px;
    color: var(--text-dim);
    transition: transform 0.2s;
    flex-shrink: 0;
  }
  .doc-section.open .doc-section-chevron { transform: rotate(90deg); }

  .doc-section-body {
    display: none;
    padding: 36px 48px 48px 40px;
    max-width: 880px;
  }
  .doc-section.open .doc-section-body { display: block; }

  /* ─── Typography ─── */
  .doc-section-body h1 {
    font-size: 1.8rem;
    font-weight: 800;
    color: var(--heading1);
    margin: 0 0 24px;
    line-height: 1.2;
    letter-spacing: -0.025em;
  }

  .doc-section-body h2 {
    font-size: 1.25rem;
    font-weight: 700;
    color: var(--heading2);
    margin: 36px 0 14px;
    letter-spacing: -0.015em;
    padding-top: 8px;
    border-top: 1px solid var(--border);
  }

  .doc-section-body h2:first-child, .doc-section-body > h1 + h2 {
    border-top: none;
    margin-top: 0;
    padding-top: 0;
  }

  .doc-section-body h3 {
    font-size: 1rem;
    font-weight: 600;
    color: var(--heading3);
    margin: 24px 0 10px;
  }

  .doc-section-body h4 {
    font-size: 0.9rem;
    font-weight: 600;
    color: var(--accent3);
    margin: 18px 0 8px;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    font-size: 0.78rem;
  }

  .doc-section-body p {
    margin: 0 0 14px;
    color: var(--text);
  }

  .doc-section-body strong { color: var(--heading2); font-weight: 600; }
  .doc-section-body em { color: var(--accent3); font-style: italic; }

  .doc-section-body ul, .doc-section-body ol {
    margin: 0 0 14px 0;
    padding-left: 24px;
  }

  .doc-section-body li {
    margin-bottom: 5px;
    color: var(--text);
  }

  .doc-section-body li > ul, .doc-section-body li > ol {
    margin: 6px 0 0 0;
  }

  /* ─── Tables ─── */
  .doc-section-body table {
    width: 100%;
    border-collapse: collapse;
    margin: 16px 0 24px;
    font-size: 0.84rem;
    border-radius: var(--radius);
    overflow: hidden;
    border: 1px solid var(--border);
  }

  .doc-section-body thead {
    background: var(--surface3);
  }

  .doc-section-body th {
    padding: 10px 14px;
    text-align: left;
    font-weight: 600;
    color: var(--heading2);
    font-size: 0.78rem;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    border-bottom: 1px solid var(--border2);
    white-space: nowrap;
  }

  .doc-section-body td {
    padding: 9px 14px;
    border-bottom: 1px solid var(--border);
    color: var(--text);
    vertical-align: top;
  }

  .doc-section-body tr:last-child td { border-bottom: none; }

  .doc-section-body tbody tr:hover td {
    background: var(--surface2);
  }

  /* ─── Code Blocks ─── */
  .doc-section-body code {
    font-family: var(--font-mono);
    font-size: 0.82em;
    background: var(--code-bg);
    border: 1px solid var(--code-border);
    border-radius: 3px;
    padding: 1px 6px;
    color: var(--accent3);
  }

  .doc-section-body pre {
    background: var(--code-bg);
    border: 1px solid var(--code-border);
    border-radius: var(--radius-lg);
    padding: 20px 24px;
    margin: 14px 0 20px;
    overflow-x: auto;
    font-family: var(--font-mono);
    font-size: 0.82rem;
    line-height: 1.65;
    color: #a8c4e0;
  }

  .doc-section-body pre code {
    background: none;
    border: none;
    padding: 0;
    color: inherit;
    font-size: inherit;
  }

  .doc-section-body pre::-webkit-scrollbar { height: 5px; }
  .doc-section-body pre::-webkit-scrollbar-track { background: transparent; }
  .doc-section-body pre::-webkit-scrollbar-thumb { background: var(--border2); border-radius: 2px; }

  /* ─── Blockquotes / Callouts ─── */
  .doc-section-body blockquote {
    border-left: 3px solid var(--accent);
    background: rgba(91,138,247,0.06);
    margin: 16px 0;
    padding: 12px 18px;
    border-radius: 0 var(--radius) var(--radius) 0;
    color: var(--text-muted);
    font-style: italic;
  }

  /* ─── Horizontal Rule ─── */
  .doc-section-body hr {
    border: none;
    border-top: 1px solid var(--border);
    margin: 28px 0;
  }

  /* ─── Status Badges in Text ─── */
  .badge {
    display: inline-flex;
    align-items: center;
    padding: 1px 7px;
    border-radius: 12px;
    font-size: 0.72rem;
    font-weight: 600;
    letter-spacing: 0.03em;
  }
  .badge-green { background: rgba(76,175,125,0.15); color: var(--green); }
  .badge-yellow { background: rgba(212,169,74,0.15); color: var(--yellow); }
  .badge-red { background: rgba(224,92,92,0.15); color: var(--red); }
  .badge-blue { background: rgba(91,138,247,0.15); color: var(--accent); }

  /* ─── Anchor links ─── */
  .anchor-link {
    display: inline-block;
    width: 16px; height: 16px;
    margin-left: 6px;
    opacity: 0;
    vertical-align: middle;
    color: var(--accent);
    text-decoration: none;
    font-size: 0.8rem;
  }
  h1:hover .anchor-link,
  h2:hover .anchor-link,
  h3:hover .anchor-link { opacity: 1; }

  /* ─── Scroll Progress ─── */
  #progress-bar {
    position: fixed;
    top: var(--header-h);
    left: 0;
    height: 2px;
    background: linear-gradient(90deg, var(--accent), var(--accent2));
    z-index: 300;
    transition: width 0.1s;
    width: 0%;
  }

  /* ─── Back to top ─── */
  #back-top {
    position: fixed;
    bottom: 28px;
    right: 28px;
    width: 40px; height: 40px;
    background: var(--surface2);
    border: 1px solid var(--border2);
    border-radius: 50%;
    color: var(--text-muted);
    cursor: pointer;
    display: flex; align-items: center; justify-content: center;
    font-size: 1.1rem;
    transition: all 0.2s;
    opacity: 0;
    pointer-events: none;
    z-index: 150;
    text-decoration: none;
    box-shadow: var(--shadow);
  }
  #back-top.visible { opacity: 1; pointer-events: auto; }
  #back-top:hover { background: var(--accent); border-color: var(--accent); color: #fff; }

  /* ─── Mobile ─── */
  @media (max-width: 900px) {
    :root { --sidebar-w: 280px; }
    .doc-section-body { padding: 24px 24px 36px; }
    .doc-section-header { padding: 18px 24px; }
    .top-bar-meta { display: none; }
  }

  @media (max-width: 600px) {
    .doc-section-body { padding: 18px 16px 28px; }
    .doc-section-header { padding: 14px 16px; }
    .doc-section-body h1 { font-size: 1.4rem; }
    .doc-section-body table { font-size: 0.78rem; }
    .doc-section-body th, .doc-section-body td { padding: 7px 10px; }
    .main-content { margin-left: 0; }
    .sidebar { transform: translateX(calc(-1 * var(--sidebar-w))); }
    .sidebar.mobile-open { transform: translateX(0); }
  }

  /* ─── Syntax Highlight Hints ─── */
  .kw { color: #a78cf5; }
  .str { color: #97d085; }
  .cmt { color: #5a6580; font-style: italic; }
  .num { color: #d4a94a; }
</style>
</head>
